                  <button
                    onClick={() => setCompressionMode('server')}
                    disabled={isProcessing || !!result}
                    className={cn(
                      'px-3 py-2 rounded-xl border text-xs font-bold transition-all',
                      compressionMode === 'server'
                        ? 'bg-primary/10 border-primary/50 text-primary'
